// ---- Router factory ----

function _chain(mws: MiddlewareHandler[]): MiddlewareHandler {
  return async (c, next) => {
    let i = 0
    // Return the result so a slot middleware that short-circuits (e.g.
    // requireResourcePolicy returning a 403/404 without calling next) propagates
    // its Response instead of being swallowed.
    const run = async (): Promise<void | Response> =>
      i < mws.length ? mws[i++](c, run as unknown as () => Promise<void>) : next()
    return run()
  }
}

